      geminiApiKey:           val('geminiApiKey'),
      geminiModel:            val('geminiModelManual')   || val('geminiModel'),
      grokServer:             val('grokServer'),
      grokApiKey:             val('grokApiKey'),
      grokModel:              val('grokModelManual')     || val('grokModel'),
